compliant_example:
void process_link_state(uint8_t state) {
    switch (state) {
        case STATE_INIT:
            init_link();
            break;
        case STATE_SYNC:
            sync_link();
            break;
        default:
            log_error("Unknown link state received.");
            break;
    }
}
